import {{ Injectable }} from '@nestjs/common';
import {{ ReviewService }} from './models/review.model';
import {{ ReviewServiceRepository }} from './repositories/review.repository';

@Injectable()
export class ReviewServiceService {{
  constructor(
    private readonly repository: ReviewServiceRepository,
  ) {{}}

  async findAll(): Promise<ReviewService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ReviewService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ReviewService>): Promise<ReviewService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ReviewService>): Promise<ReviewService> {{
    return this.repository.update(id, data);
  }}
}}
